        deprecated_versions = exports[skill_name].setdefault("deprecated_versions", [])
        if version not in deprecated_versions:
            deprecated_versions.append(version)
    else:
        exports[skill_name]["deprecated"] = True
    write_manifest(manifest_path, data)
    return {"status": "ok", "action": "deprecated", "skill": skill_name, "version": version}


def cmd_rename(manifest_path, old_name, new_name):
